      <ProtectedRoute path="/loans" component={EmployeeLoans} />
      <ProtectedRoute path="/admin/loans" component={AdminLoans} />
      <Route path="/help-us" component={HelpUs} />
      <Route component={NotFound} />
    </Switch>
  );
}

function App() {
