import { useAuth } from "@/hooks/use-auth";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useLocation } from "wouter";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import Layout from "@/components/layout/layout";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { ArrowLeft, DollarSign } from "lucide-react";

const payrollSchema = z.object({
  employeeId: z.string().min(1, "Employee is required"),
  payPeriod: z.string().min(1, "Pay period is required"),
  basicSalary: z.number().min(0, "Basic salary required"),
  overtime: z.number().optional(),
  bonus: z.number().optional(),
  deductions: z.number().optional(),
  status: z.enum(["draft", "processing", "paid"]),
});

export default function AddPayroll() {
  const { user } = useAuth();
  const [, setLocation] = useLocation();
  const { toast } = useToast();

  const { data: employees = [], isLoading } = useQuery({
    queryKey: ["employees"],
    queryFn: async () => {
      const res = await apiRequest("GET", "/api/employees");
      return res.json();
    },
  });

  const form = useForm({
    resolver: zodResolver(payrollSchema),
    defaultValues: {
      employeeId: "",
      payPeriod: "",
      basicSalary: 0,
      overtime: 0,
      bonus: 0,
      deductions: 0,
      status: "draft",
    },
  });

  const addPayrollMutation = useMutation({
    mutationFn: async (data) => {
      // Convert all numeric fields to numbers
      const basicSalary = Number(data.basicSalary) || 0;
      const overtime = Number(data.overtime) || 0;
      const bonus = Number(data.bonus) || 0;
      const deductions = Number(data.deductions) || 0;

      const netPay = basicSalary + overtime + bonus - deductions;

      const payrollData = {
        ...data,
        basicSalary,
        overtime,
        bonus,
        deductions,
        netPay,
      };

      const res = await apiRequest("POST", "/api/payrolls", payrollData);
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries(["payrolls"]);
      toast({ title: "Success", description: "Payroll created successfully" });
      setLocation("/payroll");
    },
    onError: (err) => {
      toast({ title: "Error", description: err.message, variant: "destructive" });
    },
  });

  if (user?.role !== "admin") {
    setLocation("/");
    return null;
  }

  if (isLoading) return <p>Loading employees...</p>;

  const netPay =
    Number(form.watch("basicSalary")) +
    Number(form.watch("overtime")) +
    Number(form.watch("bonus")) -
    Number(form.watch("deductions"));

  return (
    <Layout>
      <div className="space-y-6">
        <Button variant="outline" onClick={() => setLocation("/payroll")}>
          <ArrowLeft className="w-4 h-4 mr-2" /> Back
        </Button>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <DollarSign className="w-5 h-5" /> Payroll Information
            </CardTitle>
          </CardHeader>
          <CardContent>
            <form
              onSubmit={form.handleSubmit((data) => addPayrollMutation.mutate(data))}
              className="space-y-4"
            >
              {/* Employee Select */}
              <div>
                <label className="block mb-1 font-medium">Employee</label>
                <select {...form.register("employeeId")} className="w-full border p-2 rounded">
                  <option value="" disabled>Select employee</option>
                  {employees.map((emp) => (
                    <option key={emp.id} value={emp.id}>
                      {emp.firstName} {emp.lastName}
                    </option>
                  ))}
                </select>
                {form.formState.errors.employeeId && (
                  <p className="text-red-500">{form.formState.errors.employeeId.message}</p>
                )}
              </div>

              {/* Pay Period */}
              <div>
                <Input
                  placeholder="Pay Period e.g., January 2025"
                  {...form.register("payPeriod")}
                />
                {form.formState.errors.payPeriod && (
                  <p className="text-red-500">{form.formState.errors.payPeriod.message}</p>
                )}
              </div>

              {/* Salary Fields */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <Input type="number" step="0.01" {...form.register("basicSalary")} placeholder="Basic Salary" />
                <Input type="number" step="0.01" {...form.register("overtime")} placeholder="Overtime" />
                <Input type="number" step="0.01" {...form.register("bonus")} placeholder="Bonus" />
                <Input type="number" step="0.01" {...form.register("deductions")} placeholder="Deductions" />
              </div>

              {/* Net Pay */}
              <div className="p-4 bg-gray-50 rounded">
                <p className="font-bold text-green-600">Net Pay: ${netPay}</p>
              </div>

              {/* Status */}
              <div>
                <label className="block mb-1 font-medium">Status</label>
                <select {...form.register("status")} className="w-full border p-2 rounded">
                  <option value="draft">Draft</option>
                  <option value="processing">Processing</option>
                  <option value="paid">Paid</option>
                </select>
                {form.formState.errors.status && (
                  <p className="text-red-500">{form.formState.errors.status.message}</p>
                )}
              </div>

              <div className="flex space-x-4 mt-4">
                <Button type="submit">Create Payroll</Button>
                <Button type="button" variant="outline" onClick={() => setLocation("/payroll")}>
                  Cancel
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>
      </div>
    </Layout>
  );
}

client/src/pages/payroll/edit-payroll.js.content:
/**
 * 🔹 Frontend (React) - Edit Payroll Component
 * MERN Concepts Used:
 * ✅ Components - Payroll editing form with data loading
 * ✅ Props - Dynamic route params for payroll ID
 * ✅ State (useState) - Form state and real-time calculations
 * ✅ State with Object - Payroll data object and form values
 * ✅ useEffect - Loading payroll data and populating form
 * ✅ Event Handling - Form submission, calculations, navigation
 * ✅ Form Handling - Pre-populated edit form with validation
 * ✅ Form Validation - Client-side validation using Zod schema
 * ✅ Conditional Rendering - Loading states, error states, role-based access
 * ✅ React Router (Routes, Dynamic Params) - Dynamic payroll ID routing
 * ✅ Context API (for auth state) - Role-based access control
 * ✅ API Calls (fetch / axios) - GET payroll data, PUT payroll update
 * ✅ Styling (CSS / Tailwind / Bootstrap) - Form layout and responsive design
 */

import { useAuth } from "@/hooks/use-auth";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useLocation } from "wouter";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { ArrowLeft, DollarSign } from "lucide-react";
import Layout from "@/components/layout/layout";
import { useToast } from "@/hooks/use-toast";
import { useEffect } from "react";

const editPayrollSchema = z.object({
  employeeId: z.string().min(1, "Employee is required"),
  payPeriod: z.string().min(1, "Pay period is required"),
  basicSalary: z.string().min(1, "Basic salary is required"),
  overtime: z.string().optional(),
  bonus: z.string().optional(),
  deductions: z.string().optional(),
  status: z.enum(["draft", "processing", "paid"]),
});

export default function EditPayroll({ params }) {
  const { user } = useAuth();
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const { id } = params;

  const { data: payroll, isLoading: payrollLoading } = useQuery({
    queryKey: ["/api/payrolls", id],
  });

  const { data: employees, isLoading: employeesLoading } = useQuery({
    queryKey: ["/api/employees"],
  });

  const form = useForm({
    resolver: zodResolver(editPayrollSchema),
    defaultValues: {
      employeeId: "",
      payPeriod: "",
      basicSalary: "",
      overtime: "0",
      bonus: "0",
      deductions: "0",
      status: "draft",
    },
  });

  // Update form when payroll data loads
  useEffect(() => {
    if (payroll) {
      form.reset({
        employeeId: payroll.employeeId || "",
        payPeriod: payroll.payPeriod || "",
        basicSalary: payroll.basicSalary?.toString() || "",
        overtime: payroll.overtime?.toString() || "0",
        bonus: payroll.bonus?.toString() || "0",
        deductions: payroll.deductions?.toString() || "0",
        status: payroll.status || "draft",
      });
    }
  }, [payroll, form]);

  const updatePayrollMutation = useMutation({
    mutationFn: async (data) => {
      // Calculate net pay
      const basicSalary = parseFloat(data.basicSalary) || 0;
      const overtime = parseFloat(data.overtime) || 0;
      const bonus = parseFloat(data.bonus) || 0;
      const deductions = parseFloat(data.deductions) || 0;
      const netPay = basicSalary + overtime + bonus - deductions;

      const payrollData = {
        ...data,
        basicSalary,
        overtime,
        bonus,
        deductions,
        netPay,
      };

      const response = await apiRequest("PUT", `/api/payrolls/${id}`, payrollData);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/payrolls"] });
      toast({
        title: "Success",
        description: "Payroll record updated successfully",
      });
      setLocation("/payroll");
    },
    onError: (error) => {
      toast({
        title: "Error", 
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data) => {
    updatePayrollMutation.mutate(data);
  };

  // Calculate net pay in real-time
  const basicSalary = parseFloat(form.watch("basicSalary")) || 0;
  const overtime = parseFloat(form.watch("overtime")) || 0;
  const bonus = parseFloat(form.watch("bonus")) || 0;
  const deductions = parseFloat(form.watch("deductions")) || 0;
  const netPay = basicSalary + overtime + bonus - deductions;

  if (user?.role !== 'admin') {
    setLocation("/");
    return null;
  }

  if (payrollLoading || employeesLoading) {
    return (
      <Layout>
        <div className="flex items-center justify-center min-h-[400px]">
          <div className="text-center">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto"></div>
            <p className="mt-2 text-gray-600">Loading payroll data...</p>
          </div>
        </div>
      </Layout>
    );
  }

  if (!payroll) {
    return (
      <Layout>
        <div className="text-center py-12">
          <h2 className="text-2xl font-bold text-gray-900">Payroll record not found</h2>
          <p className="mt-2 text-gray-600">The payroll record you're looking for doesn't exist.</p>
          <Button
            className="mt-4"
            onClick={() => setLocation("/payroll")}
          >
            Back to Payroll
          </Button>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="space-y-6">
        <div className="flex items-center space-x-4">
          <Button
            variant="outline"
            size="sm"
            onClick={() => setLocation("/payroll")}
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back to Payroll
          </Button>
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Edit Payroll Record</h1>
            <p className="text-gray-600 mt-2">Update payroll information</p>
          </div>
        </div>

        <div className="max-w-2xl">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <DollarSign className="w-5 h-5" />
                Payroll Information
              </CardTitle>
            </CardHeader>
            <CardContent>
              <Form {...form}>
                <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
                  <FormField
                    control={form.control}
                    name="employeeId"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Employee</FormLabel>
                        <Select onValueChange={field.onChange} value={field.value}>
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Select employee" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {employees?.map((employee) => (
                              <SelectItem key={employee.id} value={employee.id}>
                                {employee.firstName} {employee.lastName} - {employee.department}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="payPeriod"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Pay Period</FormLabel>
                        <FormControl>
                          <Input placeholder="e.g., January 2024, Week 1-2" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="basicSalary"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Basic Salary</FormLabel>
                          <FormControl>
                            <Input type="number" step="0.01" placeholder="0.00" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="overtime"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Overtime Pay</FormLabel>
                          <FormControl>
                            <Input type="number" step="0.01" placeholder="0.00" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="bonus"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Bonus</FormLabel>
                          <FormControl>
                            <Input type="number" step="0.01" placeholder="0.00" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="deductions"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Deductions</FormLabel>
                          <FormControl>
                            <Input type="number" step="0.01" placeholder="0.00" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  {/* Net Pay Display */}
                  <div className="p-4 bg-gray-50 rounded-lg">
                    <label className="text-sm font-medium text-gray-700">Net Pay (Calculated)</label>
                    <p className="text-2xl font-bold text-green-600">
                      ${netPay.toFixed(2)}
                    </p>
                  </div>

                  <FormField
                    control={form.control}
                    name="status"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Status</FormLabel>
                        <Select onValueChange={field.onChange} value={field.value}>
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Select status" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="draft">Draft</SelectItem>
                            <SelectItem value="processing">Processing</SelectItem>
                            <SelectItem value="paid">Paid</SelectItem>
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <div className="flex items-center space-x-4 pt-4">
                    <Button
                      type="submit"
                      disabled={updatePayrollMutation.isPending}
                      className="bg-primary hover:bg-primary/90"
                    >
                      {updatePayrollMutation.isPending ? "Updating..." : "Update Payroll Record"}
                    </Button>
                    <Button
                      type="button"
                      variant="outline"
                      onClick={() => setLocation("/payroll")}
                    >
                      Cancel
                    </Button>
                  </div>
                </form>
              </Form>
            </CardContent>
          </Card>
        </div>
      </div>
    </Layout>
  );
}

client/src/pages/payroll/payroll-list.js.content:
/**
 * 🔹 Frontend (React) - Payroll List Component
 * MERN Concepts Used:
 * ✅ Components - Payroll management table component
 * ✅ Props - Passing data to child components and layout
 * ✅ State (useState) - Search term state management
 * ✅ State with Array - Managing payrolls and employees arrays
 * ✅ State with Object - Complex payroll and employee objects
 * ✅ useEffect - Data fetching via useQuery on component mount
 * ✅ Event Handling - Search input, delete confirmation, navigation clicks
 * ✅ Form Handling - Search functionality
 * ✅ Conditional Rendering - Role-based access, loading states, empty states
 * ✅ List Rendering (map) - Rendering payroll table rows from array
 * ✅ React Router (Routes, Dynamic Params) - Navigation to edit/add payroll
 * ✅ Context API (for auth state) - Using authentication for role checking
 * ✅ API Calls (fetch / axios) - Fetching and deleting payroll data
 * ✅ Styling (CSS / Tailwind / Bootstrap) - Table and UI styling
 */

import { useState } from "react";
import { useAuth } from "@/hooks/use-auth";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useLocation } from "wouter";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { Plus, Search, Edit, Trash2, FileDown, DollarSign } from "lucide-react";
import Layout from "@/components/layout/layout";
import { Link } from "wouter";
import { useToast } from "@/hooks/use-toast";
import { format } from "date-fns";

export default function PayrollList() {
  const { user } = useAuth();
  const [, setLocation] = useLocation();
  const [searchTerm, setSearchTerm] = useState("");
  const { toast } = useToast();

  const { data: payrolls, isLoading: payrollsLoading } = useQuery({
    queryKey: ["/api/payrolls"],
  });

  const { data: employees, isLoading: employeesLoading } = useQuery({
    queryKey: ["/api/employees"],
    enabled: user?.role === 'admin',
  });

  const deletePayrollMutation = useMutation({
    mutationFn: async (id) => {
      await apiRequest("DELETE", `/api/payrolls/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/payrolls"] });
      toast({
        title: "Success",
        description: "Payroll record deleted successfully",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const getEmployeeName = (employeeId) => {
    const employee = employees?.find(emp => emp.id === employeeId);
    return employee ? `${employee.firstName} ${employee.lastName}` : 'Unknown Employee';
  };

  const filteredPayrolls = payrolls?.filter(payroll => {
    const searchLower = searchTerm.toLowerCase();
    const employeeName = getEmployeeName(payroll.employeeId).toLowerCase();
    return (
      payroll.payPeriod.toLowerCase().includes(searchLower) ||
      employeeName.includes(searchLower)
    );
  }) || [];

  const handleDeletePayroll = (id) => {
    if (confirm('Are you sure you want to delete this payroll record?')) {
      deletePayrollMutation.mutate(id);
    }
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
    }).format(amount);
  };

  if (payrollsLoading || employeesLoading) {
    return (
      <Layout>
        <div className="flex items-center justify-center min-h-[400px]">
          <div className="text-center">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto"></div>
            <p className="mt-2 text-gray-600">Loading payroll data...</p>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="space-y-6">
        <div className="flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Payroll Management</h1>
            <p className="text-gray-600 mt-2">
              {user?.role === 'admin' 
                ? 'Manage employee payroll and salary payments' 
                : 'View your payroll history and pay slips'}
            </p>
          </div>
          {user?.role === 'admin' && (
            <Link href="/payroll/add">
              <Button className="bg-primary hover:bg-primary/90">
                <Plus className="w-4 h-4 mr-2" />
                Process Payroll
              </Button>
            </Link>
          )}
        </div>

        {/* Search */}
        <div className="flex items-center space-x-4">
          <div className="relative flex-1 max-w-sm">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-4 h-4" />
            <Input
              placeholder="Search payroll records..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-10"
            />
          </div>
        </div>

        {/* Payroll Table */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <DollarSign className="w-5 h-5" />
              Payroll Records ({filteredPayrolls.length})
            </CardTitle>
          </CardHeader>
          <CardContent>
            {filteredPayrolls.length > 0 ? (
              <div className="overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow>
                      {user?.role === 'admin' && <TableHead>Employee</TableHead>}
                      <TableHead>Pay Period</TableHead>
                      <TableHead>Basic Salary</TableHead>
                      <TableHead>Overtime</TableHead>
                      <TableHead>Deductions</TableHead>
                      <TableHead>Net Pay</TableHead>
                      <TableHead>Status</TableHead>
                      <TableHead className="text-right">Actions</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {filteredPayrolls.map((payroll) => (
                      <TableRow key={payroll.id}>
                        {user?.role === 'admin' && (
                          <TableCell className="font-medium">
                            {getEmployeeName(payroll.employeeId)}
                          </TableCell>
                        )}
                        <TableCell>{payroll.payPeriod}</TableCell>
                        <TableCell>{formatCurrency(payroll.basicSalary)}</TableCell>
                        <TableCell>{formatCurrency(payroll.overtime || 0)}</TableCell>
                        <TableCell>{formatCurrency(payroll.deductions || 0)}</TableCell>
                        <TableCell className="font-medium">
                          {formatCurrency(payroll.netPay)}
                        </TableCell>
                        <TableCell>
                          <Badge
                            className={
                              payroll.status === 'paid'
                                ? 'bg-green-100 text-green-800'
                                : payroll.status === 'processing'
                                ? 'bg-yellow-100 text-yellow-800'
                                : 'bg-gray-100 text-gray-800'
                            }
                          >
                            {payroll.status}
                          </Badge>
                        </TableCell>
                        <TableCell className="text-right">
                          <div className="flex justify-end space-x-2">
                            <Button
                              size="sm"
                              variant="outline"
                              title="Download Pay Slip"
                            >
                              <FileDown className="w-4 h-4" />
                            </Button>
                            {user?.role === 'admin' && (
                              <>
                                <Button
                                  size="sm"
                                  variant="outline"
                                  onClick={() => setLocation(`/payroll/edit/${payroll.id}`)}
                                >
                                  <Edit className="w-4 h-4" />
                                </Button>
                                <Button
                                  size="sm"
                                  variant="outline"
                                  className="text-red-600 border-red-600 hover:bg-red-50"
                                  onClick={() => handleDeletePayroll(payroll.id)}
                                  disabled={deletePayrollMutation.isPending}
                                >
                                  <Trash2 className="w-4 h-4" />
                                </Button>
                              </>
                            )}
                          </div>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>
            ) : (
              <div className="text-center py-12">
                <DollarSign className="mx-auto h-12 w-12 text-gray-400" />
                <h3 className="mt-2 text-sm font-semibold text-gray-900">No payroll records</h3>
                <p className="mt-1 text-sm text-gray-500">
                  {searchTerm ? 'No payroll records match your search.' : 'No payroll records have been processed yet.'}
                </p>
                {!searchTerm && user?.role === 'admin' && (
                  <div className="mt-6">
                    <Link href="/payroll/add">
                      <Button className="bg-primary hover:bg-primary/90">
                        <Plus className="w-4 h-4 mr-2" />
                        Process First Payroll
                      </Button>
                    </Link>
                  </div>
                )}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </Layout>
  );
}

